31	/** Wait for the 'exit' event on a handle, resolving with [code, signal]. */
32	function waitForExit(handle: SpawnHandle): Promise<[number | null, NodeJS.Signals | null]> {
33	  return new Promise((resolve) => {
34	    handle.once('exit', (code, signal) => resolve([code, signal]));
35	  });
36	}
37	
38	/** Collect all 'stderr_data' chunks until 'exit'. */
39	function collectStderr(handle: SpawnHandle): Promise<string> {
40	  return new Promise((resolve) => {
41	    let buf = '';
42	    handle.on('stderr_data', (chunk) => {
43	      buf += chunk;
44	    });
45	    handle.once('exit', () => resolve(buf));
46	  });
47	}
48	
49	/** Collect all 'stdout_line' events until 'exit'. */
50	function collectStdoutLines(handle: SpawnHandle): Promise<string[]> {
51	  return new Promise((resolve) => {
52	    const lines: string[] = [];
53	    handle.on('stdout_line', (line) => lines.push(line));
54	    handle.once('exit', () => resolve(lines));
55	  });
56	}
